import React, {Component} from 'react';


class Services extends Component{
    render(){
        return(

                 <section className="page-section" id="services">
                        <div className="container">
                            <div className="text-center">
                                <h2 className="section-heading text-uppercase">ABOUT ME</h2>
                                <h3 className="section-subheading text-muted">HELLO WORLD!</h3>
                            </div>
                            <div className="row text-center">
                            <p class="info">
                                    I am an undergrad Student at the Indian Institute of Technology Guwahati and will be graduating in 2023 with a Bachelor in Technology in Mathematics and Computing.
                                        <p  >Want to know me better?  You can find me on <a href="" >LinkedIn</a>, <a href="">Github</a> and <a href="" >Facebook.</a> you can also go through my Gmail <a href="" >ayushhrajsharma8051@gmail.com</a> </p>
                                    <h3  >Thank you!</h3>
                            </p>


                            </div>
                        </div>
                    </section>

        );
    }
}

export default Services;
